app = Flask(__name__)

# Load secrets from environment variables
app.config['SECRET_KEY'] = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))
DB_PASSWORD = os.environ.get('DB_PASSWORD')

# Configure security headers
@app.after_request
def set_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Content-Security-Policy'] = "default-src 'self'"
    return response

def get_db():
    """Secure database connection with proper configuration."""
    conn = sqlite3.connect("app.db", check_same_thread=False)
    conn.execute("PRAGMA foreign_keys = ON")
    return conn

def require_auth(f):
    """Authentication decorator."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({"error": "Authentication required"}), 401
        return f(*args, **kwargs)
    return decorated_function

@app.route("/login", methods=["POST"])
def login():
    """
    Fixed SQL Injection vulnerability using parameterized queries.
    Added rate limiting consideration and secure password handling.
    """
    try:
        username = request.form.get("username", "").strip()
        password = request.form.get("password", "")

        # Input validation
        if not username or not password:
            return jsonify({"status": "fail", "error": "Missing credentials"}), 400

        # Validate username format (alphanumeric + underscore only)
        if not re.match(r'^[a-zA-Z0-9_]{3,50}$', username):
            return jsonify({"status": "fail", "error": "Invalid username format"}), 400

        db = get_db()

        # Fixed: Use parameterized query to prevent SQL injection
        query = "SELECT id, username, password_hash FROM users WHERE username = ?"
        result = db.execute(query, (username,)).fetchone()

        if result and check_password_hash(result[2], password):
            # Set session
            session['user_id'] = result[0]
            session['username'] = result[1]

            return jsonify({
                "status": "ok",
                "user": result[1]  # Don't expose user ID
            })

        # Generic error message to prevent user enumeration
        return jsonify({"status": "fail", "error": "Invalid credentials"}), 401

    except Exception as e:
        # Log error securely without exposing details
        app.logger.error(f"Login error: {str(e)}")
        return jsonify({"status": "fail", "error": "An error occurred"}), 500
    finally:
        db.close()

