@require_auth
def run_command():
    """
    Fixed Command Injection vulnerability.
    Replaced with a whitelist approach - only allow specific safe commands.
    """
    cmd = request.args.get("cmd", "")

    # Whitelist of allowed commands
    ALLOWED_COMMANDS = {
        "status": ["systemctl", "status", "myapp"],
        "disk": ["df", "-h"],
        "memory": ["free", "-h"],
    }

    if cmd not in ALLOWED_COMMANDS:
        return jsonify({
            "error": "Command not allowed",
            "allowed": list(ALLOWED_COMMANDS.keys())
        }), 403

    # Use subprocess with argument list (not shell=True)
    import subprocess
    try:
        result = subprocess.run(
            ALLOWED_COMMANDS[cmd],
            capture_output=True,
            text=True,
            timeout=5,
            check=False
        )
        return jsonify({
