@require_auth
def read_file():
    """
    Fixed Path Traversal vulnerability.
    Uses path validation and restricts access to allowed directory.
    """
    requested_path = request.args.get("path", "").strip()

    if not requested_path:
        return jsonify({"error": "Path parameter required"}), 400

    # Define allowed base directory
    ALLOWED_DIR = Path("/var/app/data").resolve()

    try:
        # Resolve the full path and check if it's within allowed directory
        full_path = (ALLOWED_DIR / requested_path).resolve()

        # Fixed: Validate path is within allowed directory
        if not str(full_path).startswith(str(ALLOWED_DIR)):
            return jsonify({"error": "Access denied"}), 403

        # Check file exists and is a file (not directory)
        if not full_path.is_file():
            return jsonify({"error": "File not found"}), 404

        # Additional: Check file size to prevent memory issues
        file_size = full_path.stat().st_size
        MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MB
        if file_size > MAX_FILE_SIZE:
            return jsonify({"error": "File too large"}), 413

        # Read file securely
        with open(full_path, 'r', encoding='utf-8') as f:
            content = f.read()

        return jsonify({
            "path": str(full_path.relative_to(ALLOWED_DIR)),
            "content": content,
            "size": file_size
        })

    except UnicodeDecodeError:
        return jsonify({"error": "File is not text or encoding unsupported"}), 400
    except Exception as e:
        app.logger.error(f"File read error: {str(e)}")
        return jsonify({"error": "Failed to read file"}), 500

